//! Bitwise wire format for standing-wave compression metrics.
//!
//! Inter-node communication should prefer bitwise binary (zero-copy) over
//! JSON. This module defines a fixed-size 72-byte record that the consumer
//! can `mmap` and reinterpret as `&[MetricsRecord]` directly.
//!
//! Wire layout (72 bytes, 8-byte aligned, all fields little-endian):
//!
//! ```text
//! bytes  0..  3   magic 'BWMR' (Bitwise Metrics Row)
//! byte   4        version (currently 1)
//! byte   5        flags   (bit 0: float fields valid; bits 1-7 reserved)
//! bytes  6..  7   reserved (zero, padding to 8-byte boundary)
//! bytes  8.. 15   ts                 (u64 LE, unix seconds)
//! bytes 16.. 19   token_step         (u32 LE)
//! bytes 20.. 23   layer_idx          (u32 LE)
//! bytes 24.. 27   hidden_dim         (u32 LE)
//! bytes 28.. 31   standing_count     (u32 LE)
//! bytes 32.. 35   coverage           (f32 LE bits)
//! bytes 36.. 39   speedup            (f32 LE bits)
//! bytes 40.. 47   original_bytes     (u64 LE)
//! bytes 48.. 55   compressed_bytes   (u64 LE)
//! bytes 56.. 63   saved_bytes        (u64 LE)
//! bytes 64.. 71   forward_ms         (u64 LE)
//! ```
//!
//! JSON fallback row uses the same field names (lowercase, snake_case)
//! so a consumer can switch formats by sniffing the leading 4 bytes:
//! `BWMR` (0x42 0x57 0x4D 0x52) → binary; `{`  → JSON line.
//!
//! **Gestalt witnesses (tooling only):** commutative summaries over the canonical
//! 72-byte wire row mirror `bitwise::frf_witness` / `Gnosis.FrfWitnessTower`.
//! They are **not** injective and must not replace cryptographic digests.

use std::io::Write;

use bitwise::frf_witness;

pub const RECORD_SIZE: usize = 72;
pub const MAGIC: [u8; 4] = *b"BWMR";
pub const VERSION: u8 = 1;
pub const FLAG_FLOATS_VALID: u8 = 0x01;

/// One metrics record. Layout matches the wire format above byte-for-byte
/// when written via `write_le`. We do NOT use `#[repr(C)]` for direct
/// reinterpret-cast because Rust's struct layout would add padding around
/// the f32 fields after u32s; serializing field-by-field is more portable
/// and the consumer can still mmap + transmute on architectures where the
/// natural layout matches (which is true on every supported target).
#[derive(Debug, Clone, Copy)]
pub struct MetricsRecord {
    pub ts: u64,
    pub token_step: u32,
    pub layer_idx: u32,
    pub hidden_dim: u32,
    pub standing_count: u32,
    pub coverage: f32,
    pub speedup: f32,
    pub original_bytes: u64,
    pub compressed_bytes: u64,
    pub saved_bytes: u64,
    pub forward_ms: u64,
}

impl MetricsRecord {
    /// XOR parity of every bit in the canonical `to_bytes()` payload (GF(2) fold).
    #[inline]
    pub fn gestalt_xor_parity_wire(&self) -> u8 {
        frf_witness::xor_parity_bytes(&self.to_bytes())
    }

    /// Triadic merge of `(byte % 3)` across the canonical wire bytes — blind to byte permutation.
    #[inline]
    pub fn gestalt_triad_mod3_wire(&self) -> u8 {
        frf_witness::triad_merge_byte_mod3_residues(&self.to_bytes()).unwrap_or(0)
    }

    /// Serialize one record into a 72-byte little-endian buffer.
    pub fn to_bytes(&self) -> [u8; RECORD_SIZE] {
        let mut buf = [0u8; RECORD_SIZE];
        buf[0..4].copy_from_slice(&MAGIC);
        buf[4] = VERSION;
        buf[5] = FLAG_FLOATS_VALID;
        // bytes 6..7 are zero (padding)
        buf[8..16].copy_from_slice(&self.ts.to_le_bytes());
        buf[16..20].copy_from_slice(&self.token_step.to_le_bytes());
        buf[20..24].copy_from_slice(&self.layer_idx.to_le_bytes());
        buf[24..28].copy_from_slice(&self.hidden_dim.to_le_bytes());
        buf[28..32].copy_from_slice(&self.standing_count.to_le_bytes());
        buf[32..36].copy_from_slice(&self.coverage.to_bits().to_le_bytes());
        buf[36..40].copy_from_slice(&self.speedup.to_bits().to_le_bytes());
        buf[40..48].copy_from_slice(&self.original_bytes.to_le_bytes());
        buf[48..56].copy_from_slice(&self.compressed_bytes.to_le_bytes());
        buf[56..64].copy_from_slice(&self.saved_bytes.to_le_bytes());
        buf[64..72].copy_from_slice(&self.forward_ms.to_le_bytes());
        buf
    }

    /// Deserialize one record from exactly 72 bytes. Returns None if the
    /// magic or version doesn't match (so a partial write or the wrong
    /// format is detected, not silently misparsed).
    pub fn from_bytes(buf: &[u8]) -> Option<Self> {
        if buf.len() < RECORD_SIZE {
            return None;
        }
        if buf[0..4] != MAGIC {
            return None;
        }
        if buf[4] != VERSION {
            return None;
        }
        let ts = u64::from_le_bytes(buf[8..16].try_into().ok()?);
        let token_step = u32::from_le_bytes(buf[16..20].try_into().ok()?);
        let layer_idx = u32::from_le_bytes(buf[20..24].try_into().ok()?);
        let hidden_dim = u32::from_le_bytes(buf[24..28].try_into().ok()?);
        let standing_count = u32::from_le_bytes(buf[28..32].try_into().ok()?);
        let coverage = f32::from_bits(u32::from_le_bytes(buf[32..36].try_into().ok()?));
        let speedup = f32::from_bits(u32::from_le_bytes(buf[36..40].try_into().ok()?));
        let original_bytes = u64::from_le_bytes(buf[40..48].try_into().ok()?);
        let compressed_bytes = u64::from_le_bytes(buf[48..56].try_into().ok()?);
        let saved_bytes = u64::from_le_bytes(buf[56..64].try_into().ok()?);
        let forward_ms = u64::from_le_bytes(buf[64..72].try_into().ok()?);
        Some(MetricsRecord {
            ts,
            token_step,
            layer_idx,
            hidden_dim,
            standing_count,
            coverage,
            speedup,
            original_bytes,
            compressed_bytes,
            saved_bytes,
            forward_ms,
        })
    }

    /// JSON line representation (for the fallback path). Same field names
    /// as the binary fields, no nesting.
    pub fn to_json_line(&self) -> String {
        format!(
            "{{\"ts\":{},\"token_step\":{},\"layer_idx\":{},\"hidden_dim\":{},\"standing_count\":{},\"coverage\":{:.6},\"speedup\":{:.6},\"original_bytes\":{},\"compressed_bytes\":{},\"saved_bytes\":{},\"forward_ms\":{}}}\n",
            self.ts,
            self.token_step,
            self.layer_idx,
            self.hidden_dim,
            self.standing_count,
            self.coverage,
            self.speedup,
            self.original_bytes,
            self.compressed_bytes,
            self.saved_bytes,
            self.forward_ms,
        )
    }
}

/// Sink trait so live-inference can write to either format without
/// branching at every record.
pub trait MetricsSink {
    fn write_record(&mut self, rec: &MetricsRecord) -> std::io::Result<()>;
    fn flush(&mut self) -> std::io::Result<()>;
}

/// Binary sink: writes 72-byte records back to back. The output file is
/// `floor(file_size / 72)` records, no padding, no terminator.
pub struct BinarySink<W: Write> {
    w: W,
}
impl<W: Write> BinarySink<W> {
    pub fn new(w: W) -> Self {
        Self { w }
    }
}
impl<W: Write> MetricsSink for BinarySink<W> {
    fn write_record(&mut self, rec: &MetricsRecord) -> std::io::Result<()> {
        self.w.write_all(&rec.to_bytes())
    }
    fn flush(&mut self) -> std::io::Result<()> {
        self.w.flush()
    }
}

/// JSON sink: writes one JSON line per record.
pub struct JsonSink<W: Write> {
    w: W,
}
impl<W: Write> JsonSink<W> {
    pub fn new(w: W) -> Self {
        Self { w }
    }
}
impl<W: Write> MetricsSink for JsonSink<W> {
    fn write_record(&mut self, rec: &MetricsRecord) -> std::io::Result<()> {
        self.w.write_all(rec.to_json_line().as_bytes())
    }
    fn flush(&mut self) -> std::io::Result<()> {
        self.w.flush()
    }
}

/// Tee sink: writes each record to TWO sinks (e.g., binary primary +
/// JSON fallback). Both writes must succeed; the first failure aborts.
pub struct TeeSink<A: MetricsSink, B: MetricsSink> {
    pub primary: A,
    pub fallback: B,
}
impl<A: MetricsSink, B: MetricsSink> MetricsSink for TeeSink<A, B> {
    fn write_record(&mut self, rec: &MetricsRecord) -> std::io::Result<()> {
        self.primary.write_record(rec)?;
        self.fallback.write_record(rec)
    }
    fn flush(&mut self) -> std::io::Result<()> {
        self.primary.flush()?;
        self.fallback.flush()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn round_trip_binary() {
        let rec = MetricsRecord {
            ts: 1_714_676_400,
            token_step: 7,
            layer_idx: 12,
            hidden_dim: 4096,
            standing_count: 1248,
            coverage: 0.3047,
            speedup: 3.282,
            original_bytes: 16_384,
            compressed_bytes: 4_992,
            saved_bytes: 11_392,
            forward_ms: 47,
        };
        let buf = rec.to_bytes();
        assert_eq!(buf.len(), RECORD_SIZE);
        assert_eq!(&buf[0..4], &MAGIC);
        assert_eq!(buf[4], VERSION);
        let parsed = MetricsRecord::from_bytes(&buf).expect("parse");
        assert_eq!(parsed.ts, rec.ts);
        assert_eq!(parsed.token_step, rec.token_step);
        assert_eq!(parsed.layer_idx, rec.layer_idx);
        assert_eq!(parsed.hidden_dim, rec.hidden_dim);
        assert_eq!(parsed.standing_count, rec.standing_count);
        assert!((parsed.coverage - rec.coverage).abs() < 1e-6);
        assert!((parsed.speedup - rec.speedup).abs() < 1e-6);
        assert_eq!(parsed.original_bytes, rec.original_bytes);
        assert_eq!(parsed.compressed_bytes, rec.compressed_bytes);
        assert_eq!(parsed.saved_bytes, rec.saved_bytes);
        assert_eq!(parsed.forward_ms, rec.forward_ms);
        assert_eq!(
            rec.gestalt_xor_parity_wire(),
            parsed.gestalt_xor_parity_wire()
        );
        assert_eq!(
            rec.gestalt_triad_mod3_wire(),
            parsed.gestalt_triad_mod3_wire()
        );
    }

    #[test]
    fn gestalt_witnesses_stable_on_fixture() {
        let rec = MetricsRecord {
            ts: 1_714_676_400,
            token_step: 7,
            layer_idx: 12,
            hidden_dim: 4096,
            standing_count: 1248,
            coverage: 0.3047,
            speedup: 3.282,
            original_bytes: 16_384,
            compressed_bytes: 4_992,
            saved_bytes: 11_392,
            forward_ms: 47,
        };
        assert_eq!(rec.gestalt_xor_parity_wire(), rec.gestalt_xor_parity_wire());
        assert_eq!(rec.gestalt_triad_mod3_wire(), rec.gestalt_triad_mod3_wire());
    }

    #[test]
    fn rejects_wrong_magic() {
        let mut buf = [0u8; RECORD_SIZE];
        buf[0..4].copy_from_slice(b"WRNG");
        assert!(MetricsRecord::from_bytes(&buf).is_none());
    }

    #[test]
    fn rejects_wrong_version() {
        let rec = MetricsRecord {
            ts: 0,
            token_step: 0,
            layer_idx: 0,
            hidden_dim: 0,
            standing_count: 0,
            coverage: 0.0,
            speedup: 0.0,
            original_bytes: 0,
            compressed_bytes: 0,
            saved_bytes: 0,
            forward_ms: 0,
        };
        let mut buf = rec.to_bytes();
        buf[4] = 99; // wrong version
        assert!(MetricsRecord::from_bytes(&buf).is_none());
    }

    #[test]
    fn json_line_is_one_line_terminated() {
        let rec = MetricsRecord {
            ts: 1,
            token_step: 2,
            layer_idx: 3,
            hidden_dim: 4,
            standing_count: 5,
            coverage: 0.5,
            speedup: 2.0,
            original_bytes: 16,
            compressed_bytes: 8,
            saved_bytes: 8,
            forward_ms: 1,
        };
        let line = rec.to_json_line();
        assert!(line.ends_with('\n'));
        assert_eq!(line.matches('\n').count(), 1);
        assert!(line.starts_with('{'));
    }
}
